mapper.select:
SELECT q.POST_SN , q.QNA_CTG_CD , q.SECR_YN , q.ANSW_STAT_CD , q.ANSW_CN , q.ANSWR_USER_ID , q.ANSW_DT , b.POST_SJ , b.POST_CN , b.WRTR_USER_ID , b.REG_DT , b.MDFCN_DT , c1.COM_CD_NM AS QNA_CTG_NM , c2.COM_CD_NM AS ANSW_STAT_NM FROM QNA q JOIN BOARD b ON b.POST_SN = q.POST_SN LEFT JOIN COM_CD c1 ON c1.CL_CODE = '105' AND c1.COM_CD = q.QNA_CTG_CD LEFT JOIN COM_CD c2 ON c2.CL_CODE = '104' AND c2.COM_CD = q.ANSW_STAT_CD
AND q.QNA_CTG_CD = #{qnaCtgCd}
AND q.ANSW_STAT_CD = #{answStatCd}
ORDER BY b.REG_DT DESC

mapper.insert:
INSERT INTO QNA (
    POST_SN
    , QNA_CTG_CD
    , SECR_YN
    , ANSW_STAT_CD
) VALUES (
    #{postSn}
    , #{qnaCtgCd, jdbcType=CHAR}
    , #{secrYn, jdbcType=CHAR}
    , '01'
)

mapper.update:
UPDATE QNA
SET
    QNA_CTG_CD = #{qnaCtgCd, jdbcType=CHAR}
    , SECR_YN = #{secrYn, jdbcType=CHAR}
WHERE POST_SN = #{postSn}

UPDATE QNA
SET
    ANSW_STAT_CD = '02'
    , ANSW_CN = #{answCn}
    , ANSWR_USER_ID = #{answrUserId}
    , ANSW_DT = CURRENT_TIMESTAMP
WHERE POST_SN = #{postSn}
